import React from 'react';
import uuid from '../../../utils/uuid';
import Container from '../../atoms/Container';

type Site = {
  href: string;
  title: string;
  icon: any;
};

export type FooterProps = {
  sites: Array<Site>;
};

const Footer: React.FC<FooterProps> = ({ sites }) => {
  const year: number = new Date().getFullYear();
  return (
    <footer className="border-t p-4 bg-gray-900 text-white">
      <Container>
        <div className="block md:flex justify-between">
          <p>&copy; {year} Hieu Doan. All rights reserved</p>
          <div className="flex items-center">
            {sites.map((site: Site) => {
              const { href, title, icon } = site;
              return (
                <a
                  key={uuid()}
                  href={href}
                  title={title}
                  target="_blank"
                  rel="noreferrer"
                  className="mr-2 md:ml-2"
                >
                  {icon}
                </a>
              );
            })}
          </div>
        </div>
      </Container>
    </footer>
  );
};

export default Footer;
